var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하아…… 하……","JPN":"はあ……は……","ENG":"*Huff...* *Huff...*","TWN":"呼呼……呼……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"팔 하나로 검을 휘두르는 것은 한계가 명확하다.","JPN":"腕一本で刀を振るうのは限界がある。","ENG":"There is only so much one can do whilst wielding a sword with one hand.","TWN":"光靠一隻手臂要揮劍還是很有限的。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"고작 이런 힘으로는 당주님을 지키지 못해.","JPN":"こんな力では、当主を守れない。","ENG":"I will not be able to protect Lady Nanahara like this.","TWN":"我這樣是無法保護堂主的。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 이걸 사용한다면…….","JPN":"だが、これを使えば……","ENG":"But if I use this...","TWN":"但是用這個的話……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"비록 영혼을 해치는 힘이라고는 하나……","JPN":"たとえ魂を損ねる力であっても……","ENG":"Even if its power destroys my soul...","TWN":"雖然這股力量對靈魂有害……"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"한계에 부딪혀 그 힘이 반드시 필요한 때가 오겠지.","JPN":"限界に達して、その力が必要になるときが来るだろう。","ENG":"There will be a time when I reach my limit and require its assistance.","TWN":"但當我面對到極限時就會需要它吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"그 앰플은 어디에서 난 거지?","JPN":"そのアンプルはどこから持ってきたのじゃ？","ENG":"Where did you get that ampule?","TWN":"你是從哪拿到那個東西的？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……누구냐?!","JPN":"……何者だ！？","ENG":"...Who goes there?!","TWN":"……是誰？！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"무슨 생각을 하는지 표정에서 다 드러나는구나, 하야미의 제자야.","JPN":"何を考えているのか全部顔に書いてあるのう、速水の弟子。","ENG":"Your expression says everything about what you're thinking, apprentice of Hayami.","TWN":"速水的徒弟，你想什麼都寫在你的臉上呢。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나오님……?","JPN":"ナオ様……？","ENG":"Miss Nao...?","TWN":"奈緒大人……？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그건 힘의 원천 같은 게 아니다. 너를 영혼 없는 괴물로 만들 뿐이지.","JPN":"それは力の源なんかではない。お主を魂なき化け物にするだけじゃ。","ENG":"That is not a solution to getting stronger. It will only erode your soul and turn you into a monster.","TWN":"它不是力量的來源，它只會把你變成沒有靈魂的怪物。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만…… 그런 힘이 없으면 명부검을 휘두를 수조차 없습니다.","JPN":"しかし……そういう力がなければ、冥府剣を振るうことすらできません。","ENG":"But without... I cannot even unsheathe this sword.","TWN":"可是……沒有它，我連拿起冥府劍的力量都沒有。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"휘두르지 못하는 검으로는 아무것도 베지 못합니다.","JPN":"振るえない刀では何も斬ることができません。","ENG":"Being unable to wield it, I cannot strike anything.","TWN":"我拿不起劍就無法砍殺任何人。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"네가 원하는 힘이란 것은, 고작 적을 베기 위해서 필요한 것이냐?","JPN":"お主の望む力とは、たかが敵を斬るためだけに必要なものなのか？","ENG":"This power you seek, do you want it for the sole purpose of cutting down enemies?","TWN":"你之所以需要那股力量，只是因為要砍殺敵人嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……예?","JPN":"……はい？","ENG":"...Come again?","TWN":"……什麼？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"검은 다만 벨 뿐이지만, 검술은 자고로 사람이 자신의 소중한 것을 지키기 위해 배우는 것.","JPN":"刀はただ斬るだけじゃが、剣術とは大切なものを守るために教わるものじゃ。","ENG":"A sword is meant to slice, but we hone the swordsmanship in order to protect the ones around us.","TWN":"劍是拿來砍的沒錯，但自古以來人們之所以學習劍法，是因為要保護自己心愛的東西。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"내 말이 틀리냐?","JPN":"違うか？","ENG":"Am I wrong?","TWN":"我有說錯嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"지키기 위해…… 배우는 것.","JPN":"守るために……教わるもの。","ENG":"Hone... to protect the ones around us.","TWN":"為保護……而學的。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"지금부터 제가 가르칠 것은 하야미 가문이 오래 전 명부신에게 전수받은 검술입니다.","JPN":"これより私が教えるのは速水家が昔、冥府の神より授かった剣術です。","ENG":"What I am about to teach you now is the swordsmanship that the Hayami family learned from the Nether God generations ago.","TWN":"現在開始我要教您的，是速水家族很久以前傳承自冥府神的劍法。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"나나하라류의 원천은 세상의 온갖 악의로부터 이승을 지키고자 했던 명부신이 만든 검술.","JPN":"七原流の根本は世の中のあらゆる悪意からこの世を守ろうとした冥府の神が作った剣術。","ENG":"The Nanahara style was made by the Nether God to protect this world from all evil.","TWN":"冥府神創造這套劍法的目的，是要從世界的萬惡中守護現世，這也是七原流的根本。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"누군가를 베겠다는 마음을 품고 검을 휘두른다면, 한계에 부딪히고 말 겁니다.","JPN":"誰かを斬るという気持ちで刀を振るうなら、限界が訪れるでしょう。","ENG":"The moment you decide you are going to slash someone, you will hit a brick wall.","TWN":"若您拿劍的目的是要殺人，那就一定會遇到瓶頸。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"지켜야 할 것을 알고 검을 휘두르는 것. 그것이 나나하라류의 극의에 다다르기 위한 마음가짐이지요.","JPN":"守るべきものを知って刀を振るうこと。それが七原流の極意に届くための心得なのです。","ENG":"You must have in mind what you want to protect before unsheathing. That is how one reaches the pinnacle of the Nanahara style.","TWN":"當您很清楚所要保護的是什麼才拿起劍，這樣的心志才能使您達到七原流的極致。"},"stage":{"bg":"SKY","bgm":"THEMA_NANAHARA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나오님의 말씀이 맞습니다.","JPN":"ナオ様のおっしゃる通りです。","ENG":"You are right, Miss Nao.","TWN":"奈緒大人說的沒錯。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제가 검을 쥔 것은 힘을 얻기 위해서가 아닌 당주님을 지키기 위해서였으니까요.","JPN":"私が刀を持ったのは、力を得るためではなく当主を守るためでしたから。","ENG":"I bear this sword, not to earn strength, but to protect Lady Nanahara.","TWN":"我拿起劍的目的不是要得到力量，而是要保護堂主。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"당주를 지키기 위해서라고? 자기 자신에게 그렇게 솔직하지 못해서야 못쓰겠구나.","JPN":"当主を守るためじゃと？　自分にそこまで素直じゃないとは、使えないやつじゃ。","ENG":"Protect Lady Nanahara? You should be franker with yourself.","TWN":"保護堂主？你這樣不行喔，對自己一點也不誠實。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……예?","JPN":"……はい？","ENG":"...Pardon?","TWN":"……什麼？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"당주가 살아있음의 의미는 가문연합을 계속 이끌어가기 위함이다.","JPN":"当主が生きる意味は連合を存続させていくことにあるのじゃ。","ENG":"The head is there as a symbol of the Family Alliance and to lead it.","TWN":"堂主活著的意義，在於能夠持續帶領家族聯盟，"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"당주가 죽더라도 네가 그 자릴 이으면 돼.","JPN":"当主が死んでも、お主が跡を継げばよい。","ENG":"If the current head dies, all you need to do is take her place.","TWN":"但就算堂主死掉，只要你坐上堂主的位置就沒什麼問題。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나오님, 어찌 그런 말씀을……!","JPN":"ナオ様、どうしてそのようなお言葉を……！","ENG":"Miss Nao, how can you say that...?!","TWN":"奈緒大人，您怎麼可以這麼說……！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하지만.","JPN":"じゃが。","ENG":"However.","TWN":"不過！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L42_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"네가 죽으면 차기 당주도 없고, 역신베기가 완성될 기회마저 함께 잃고 만다.","JPN":"お主が死ねば次期当主もいなくなり、大蛇薙剣が完成する機会までなくなってしまう。","ENG":"If you die, there is no successor, and we lose our chance to finish Orochinagi.","TWN":"要是你死掉，又沒人可以繼承堂主的位置，完成瘟神斬的可能性也幾乎是零。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"철저히 가문연합만을 위한다면, 과연 어느 쪽의 목숨이 우선이겠느냐?","JPN":"連合のためだけを考えれば、はたしてどちらの命を優先すべきかのう？","ENG":"If you are thinking purely for the Alliance, which life would you prioritize first?","TWN":"那你說說看，要顧全家族聯盟的話，究竟是誰的命比較重要？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그건……!","JPN":"それは……！","ENG":"That’s...!","TWN":"這……！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"태스크포스 노아의 소재를 파악했습니다.","JPN":"タスクフォース・ノアの所在を把握いたしました。","ENG":"TASKFORCE NOA's whereabouts have been confirmed.","TWN":"已經掌握到特遣勢力諾亞的位置。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"오, 정말이냐? 지금 어디에 숨어있지?","JPN":"お、本当か？　どこに隠れておる？","ENG":"Oh, is that so? So where are they hiding?","TWN":"喔，真的嗎？他們躲在哪裡？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"숨어있지도 않더군요.","JPN":"隠れてもいませんでした。","ENG":"They were not hiding at all.","TWN":"他們沒有躲起來，"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"지금 병력을 이끌고 제8봉인역으로 향하는 중입니다.","JPN":"現在、兵力を率いて第8封印域へと向かっています。","ENG":"They are leading their troops and headed towards the 8th Seal Domain.","TWN":"他們正率兵前往第8封印域。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};